INSERT INTO comment     /* 댓글 테이블 */
(
    note_id             /* 테이스팅 노트 키 */
  , user_id             /* 회원 키 */
  , parent_comment_id   /* 부모 댓글 키 */
  , group_id            /* 댓글 그룹 ID */
  , depth               /* 댓글 깊이 */
  , content             /* 댓글 내용 */
  , created_at          /* 등록 일시 */
)
VALUES
(
    #{noteId}
  , #{userId}
  , #{parentCommentId}
  , 0
  , 0
  , #{content}
  , NOW()
)

INSERT INTO comment        /* 댓글 테이블 */
(
    note_id             /* 테이스팅 노트 키 */
  , user_id             /* 회원 키 */
  , parent_comment_id   /* 부모 댓글 키 */
  , group_id            /* 댓글 그룹 ID */
  , depth               /* 댓글 깊이 */
  , content             /* 댓글 내용 */
  , created_at          /* 등록 일시 */
)
VALUES
(
    #{noteId}
  , #{userId}
  , #{parentCommentId}
  , #{groupId}
  , #{depth}
  , #{content}
  , NOW()
)

mapper.update:
UPDATE comment                      /* 댓글 테이블 */
   SET content    = #{content}      /* 댓글 내용 */
     , updated_at = NOW()           /* 수정 일시 */
 WHERE comment_id = #{commentId}
   AND user_id    = #{userId}
   AND is_deleted = 'N'
